public interface IDiscountStrategy {
  decimal Apply(decimal amount);
}

public class NoDiscount : IDiscountStrategy {
  public decimal Apply(decimal amount) => amount;
}

public class PercentageDiscount : IDiscountStrategy {
  private readonly decimal _rate;
  public PercentageDiscount(decimal rate) { _rate = rate; }
  public decimal Apply(decimal amount) => amount * (1 - _rate);
}

public class PricingContext {
  private IDiscountStrategy _strategy;
  public PricingContext(IDiscountStrategy strategy) { _strategy = strategy; }
  public void SetStrategy(IDiscountStrategy strategy) { _strategy = strategy; }
  public decimal Calculate(decimal amount) => _strategy.Apply(amount);
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Context_UsesConfiguredStrategy() {
  var context = new PricingContext(new NoDiscount());
  Assert.AreEqual(100m, context.Calculate(100m));
  context.SetStrategy(new PercentageDiscount(0.2m));
  Assert.AreEqual(80m, context.Calculate(100m));
}

[TestMethod]
public void PercentageDiscount_AppliesRate() {
  var strategy = new PercentageDiscount(0.1m);
  Assert.AreEqual(90m, strategy.Apply(100m));
}
